let smtpConfigData={};async function loadSmtpConfig(){try{const t=await fetch("api/admin.php?action=get_smtp_config",{credentials:"same-origin"});if(!t.ok)throw new Error(`HTTP ${t.status}`);const e=await t.json();"success"===e.status?(smtpConfigData=e.data,document.getElementById("smtp_host").value=smtpConfigData.smtp_host||"",document.getElementById("smtp_port").value=smtpConfigData.smtp_port||"587",document.getElementById("smtp_username").value=smtpConfigData.smtp_username||"",document.getElementById("smtp_password").value=smtpConfigData.smtp_password||"",document.getElementById("smtp_encryption").value=smtpConfigData.smtp_encryption||"tls",document.getElementById("smtp_from").value=smtpConfigData.smtp_from||"reklamace@wgs-service.cz",document.getElementById("smtp_from_name").value=smtpConfigData.smtp_from_name||"White Glove Service"):(console.error("Chyba při načítání SMTP konfigurace:",e.message),wgsToast.error("Chyba při načítání SMTP konfigurace: "+e.message))}catch(t){console.error("Load SMTP config error:",t),wgsToast.error("Chyba při načítání SMTP konfigurace")}}async function saveSmtpConfig(){const t=await getCSRFToken(),e={smtp_host:document.getElementById("smtp_host").value.trim(),smtp_port:document.getElementById("smtp_port").value.trim(),smtp_username:document.getElementById("smtp_username").value.trim(),smtp_password:document.getElementById("smtp_password").value,smtp_encryption:document.getElementById("smtp_encryption").value,smtp_from:document.getElementById("smtp_from").value.trim(),smtp_from_name:document.getElementById("smtp_from_name").value.trim(),csrf_token:t};if(!e.smtp_host)return void wgsToast.warning("Vyplňte SMTP server");if(!e.smtp_username)return void wgsToast.warning("Vyplňte uživatelské jméno");const n=document.getElementById("saveSmtpBtn"),o=n.textContent;n.disabled=!0,n.textContent="Ukládání...";try{const t=await fetch("api/admin.php?action=save_smtp_config",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(e),credentials:"same-origin"});if(!t.ok)throw new Error(`HTTP ${t.status}`);const n=await t.json();"success"===n.status?wgsToast.success("SMTP konfigurace byla uložena"):wgsToast.error("Chyba: "+n.message)}catch(t){console.error("Save SMTP config error:",t),wgsToast.error("Chyba při ukládání SMTP konfigurace")}finally{n.disabled=!1,n.textContent=o}}async function testSmtpConnection(){const t=document.getElementById("testSmtpBtn"),e=t.textContent;t.disabled=!0,t.textContent="Testování...";try{const t=await getCSRFToken();if(!t)throw wgsToast.error("CSRF token nebyl nalezen - session problém v Safari iframe"),new Error("CSRF token nebyl nalezen");const e=await fetch("api/admin.php?action=test_smtp_connection",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({csrf_token:t}),credentials:"same-origin"});if(403===e.status){const t=await e.json();throw console.error("403 Error details:",t),wgsToast.error(`CSRF validace selhala: ${JSON.stringify(t.debug||{})}`),new Error(`HTTP 403 - ${t.message||"CSRF validation failed"}`)}if(!e.ok)throw new Error(`HTTP ${e.status}`);const n=await e.text();let o;try{o=JSON.parse(n)}catch(t){throw console.error("JSON parse failed:",t),console.error("Full response:",n),wgsToast.error("Server vrátil neplatnou odpověď (ne JSON). Zkontrolujte konzoli pro detaily."),new Error(`Invalid JSON response: ${t.message}`)}"success"===o.status?wgsToast.success(o.message):wgsToast.error("Test selhal: "+o.message)}catch(t){console.error("Test SMTP error:",t),wgsToast.error("Chyba při testování SMTP připojení")}finally{t.disabled=!1,t.textContent=e}}async function getCSRFToken(){let t=document.querySelector('meta[name="csrf-token"]');if(!t&&window.parent&&window.parent!==window)try{t=window.parent.document.querySelector('meta[name="csrf-token"]')}catch(t){console.warn("Cannot access parent document for CSRF token:",t)}if(!t)return console.warn("No CSRF meta tag found"),null;const e=t.getAttribute("content");return e&&"string"==typeof e&&e.length>0?String(e):null}